    check_condition[i1] = m[i1*BITSIZE_S_addr_ram +:BITSIZE_S_addr_ram] == ALLOCATED_ADDRESS;
  end
end
endfunction
function [BITSIZE_out1-1:0] extract_value;
  input [PORTSIZE_S_addr_ram-1:0] cond;
  input [PORTSIZE_S_Wdata_ram*BITSIZE_S_Wdata_ram-1:0] value;
  reg [BITSIZE_out1-1:0] res;
  integer i1;
begin
  res={BITSIZE_out1{1'b0}};
  for(i1 = 0; i1 < PORTSIZE_S_Wdata_ram; i1 = i1 + 1)
  begin
    res = res | ( cond[i1] ? value[i1*BITSIZE_S_Wdata_ram +:BITSIZE_S_Wdata_ram] : {BITSIZE_out1{1'b0}});
  end
  extract_value = res;
end
endfunction
