reg state 1INIT_ZERO_VALUE;
reg next_state;

assign Mout_oe_ram = Min_oe_ram;
assign Mout_we_ram = state ? 1'b1 : Min_we_ram;
assign Mout_addr_ram = state ? notifyAddress : Min_addr_ram;
assign Mout_Wdata_ram = state ? {{BITSIZE_Mout_Wdata_ram - 1{1'b0}}, 1'b1} : Min_Wdata_ram;
assign Mout_data_ram_size = state ?  4'd8 : Min_data_ram_size;

generate 
  if (EMULATE_BRAM) 
  begin    
    assign notified = state ? (Mout_we_ram || Mout_oe_ram) : ~(& notifyAddress);

    always @ (*) 
    begin
      next_state = state;
      if (state == 1'b0) 
      begin
        if ((| notifyAddress) & done_port) 
        begin
            next_state = 1'b1;
        end
      end
      else 
      begin
        if (Mout_we_ram || Mout_oe_ram) 
        begin
            next_state = 1'b0;
        end
      end
    end
  end
  else
  begin
    assign notified = state ? M_DataRdy : ~(& notifyAddress);

    always @ (*) 
    begin
      next_state = state;
      if (state == 1'b0) 
      begin
        if ((| notifyAddress) & done_port) 
        begin
            next_state = 1'b1;
        end
      end
      else 
      begin
        if (M_DataRdy == 1'b1) 
        begin
            next_state = 1'b0;
        end
      end
    end
  end
endgenerate

always @ (posedge clock 1RESET_EDGE) begin
  if (1RESET_VALUE) begin
    state <= 1'b0;
  end
  else begin
    state <= next_state;
  end
end

