assign out1 = in1;
assign internal = check_condition(S_addr_ram);
assign Sout_DataRdy = oe_ack | Sin_DataRdy;
assign Sout_Rdata_ram = inject_value(internal_previous, register, Sin_Rdata_ram);

assign oe_ack_next = internal & ~oe_ack;
always @(posedge clock 1RESET_EDGE)
begin
  if (1RESET_VALUE)
  begin
    register <= {BITSIZE_in1{1'b0}};
    oe_ack <= {PORTSIZE_S_addr_ram{1'b0}};
    internal_previous <= {PORTSIZE_S_addr_ram{1'b0}};
  end
  else
  begin
    if (done_port)
      register <= in1;
    oe_ack <= oe_ack_next;
