wire [BITSIZE_S_addr_ram - 1:0] statusRegister;
reg [BITSIZE_S_addr_ram - 1:0]  ackAddress 1INIT_ZERO_VALUE;
reg [BITSIZE_S_addr_ram - 1:0]  ackAddress_next;
reg [1:0]   state 1INIT_ZERO_VALUE;
reg [1:0]   state_next;

reg [BITSIZE_Sout_Rdata_ram-1:0] Sout_Rdata_ram;
reg                              Sout_DataRdy;
reg                              start_port 1INIT_ZERO_VALUE;
reg                              next_start_port;

wire       internal;

assign control = statusRegister[0];
assign internal = S_addr_ram == ALLOCATED_ADDRESS;
assign statusRegister = {ackAddress[BITSIZE_S_addr_ram - 1:2], state};
assign notifyAddress = {ackAddress[BITSIZE_S_addr_ram-1:2], 2'd0};

always @ (*) begin
   Sout_Rdata_ram = Sin_Rdata_ram;
   Sout_DataRdy = Sin_DataRdy;
   ackAddress_next = ackAddress;
   if (internal) begin
      Sout_DataRdy = 1'b1;
      if (S_oe_ram)
        Sout_Rdata_ram = statusRegister;
      if (S_we_ram)
        ackAddress_next = {S_Wdata_ram[BITSIZE_S_Wdata_ram - 1:2], 2'b0};
   end
end // always @ (*)

always @ (posedge clock 1RESET_EDGE) begin
   if (1RESET_VALUE) begin
      state <= 2'd0;
      ackAddress <= 32'd0;
      start_port <= 1'b0;
   end else begin
      state <= state_next;
      ackAddress <= ackAddress_next;
      start_port <= next_start_port;
   end
end   

always @ (*) begin
   state_next = state;
   next_start_port = 1'b0;

   if (state == 2'd0) begin
      if (internal & S_we_ram) begin
         state_next = 2'd1;
         next_start_port = 1'b1;
      end
   end else if (state == 2'd1) begin
      if (done_port) begin
         state_next = 2'd2;
      end
   end else if (state == 2'd2) begin
      if (notified) begin
         state_next = 2'd0;
      end
   end else begin
   end
end

